import{_ as r,C as s,o as n,c as i,a7 as a,E as o}from"./chunks/framework.C5fSpjcB.js";const b=JSON.parse('{"title":"Awakeners","description":"","frontmatter":{},"headers":[],"relativePath":"en/awakeners/index.md","filePath":"en/awakeners/index.md","lastUpdated":1775394001000}'),l={name:"en/awakeners/index.md"};function d(h,e,m,c,p,g){const t=s("CharacterGrid");return n(),i("div",null,[e[0]||(e[0]=a('<h1 id="awakeners" tabindex="-1">Awakeners <a class="header-anchor" href="#awakeners" aria-label="Permalink to &quot;Awakeners&quot;">​</a></h1><p><strong>Awakeners</strong> (唤醒体) are the playable characters in Morimens. Each Awakener belongs to a Designated Realm and fulfills a combat role on your team.</p><h2 id="rarity" tabindex="-1">Rarity <a class="header-anchor" href="#rarity" aria-label="Permalink to &quot;Rarity&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rarity</th><th>Pull Rate</th><th>Notes</th></tr></thead><tbody><tr><td><span class="rarity-ssr">SSR</span></td><td>3%</td><td>Highest rarity; 30-pull pity guaranteed</td></tr><tr><td><span class="rarity-sr">SR</span></td><td>—</td><td>Mid-tier rarity</td></tr><tr><td><span class="rarity-r">R</span></td><td>—</td><td>Common rarity</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The SSR rate was increased from 1% to 3% during development, making Morimens one of the more generous gacha games on the market.</p></div><h2 id="designated-realms" tabindex="-1">Designated Realms <a class="header-anchor" href="#designated-realms" aria-label="Permalink to &quot;Designated Realms&quot;">​</a></h2><p>Every Awakener is aligned with one of four Designated Realms:</p><table tabindex="0"><thead><tr><th>Realm</th><th>Description</th></tr></thead><tbody><tr><td><span class="realm-badge realm-chaos">Chaos</span></td><td>Flexible realm that mixes cards from multiple realms and boosts Silver Key generation</td></tr><tr><td><span class="realm-badge realm-aequor">Aequor</span></td><td>Deep-sea realm focused on summoning Tentacle entities</td></tr><tr><td><span class="realm-badge realm-caro">Caro</span></td><td>Flesh realm that creates and consumes Embryo cards</td></tr><tr><td><span class="realm-badge realm-ultra">Ultra</span></td><td>Dimensional realm that gains extra turns from playing cards</td></tr></tbody></table><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><p>Awakeners fill one of three combat roles:</p><ul><li><strong>DPS</strong> — Primary damage dealers. High Attack stats, offensive card kits.</li><li><strong>Tank</strong> — Frontline defenders. High Constitution and Defense stats, protective abilities.</li><li><strong>Support</strong> — Utility and healing. Buff allies, debuff enemies, restore HP or provide shields.</li></ul><h2 id="base-stats" tabindex="-1">Base Stats <a class="header-anchor" href="#base-stats" aria-label="Permalink to &quot;Base Stats&quot;">​</a></h2><p>Every Awakener has three core stats:</p><table tabindex="0"><thead><tr><th>Stat</th><th>Description</th></tr></thead><tbody><tr><td><strong>Constitution (CON)</strong></td><td>Determines maximum HP</td></tr><tr><td><strong>Attack (ATK)</strong></td><td>Determines damage output</td></tr><tr><td><strong>Defense (DEF)</strong></td><td>Reduces incoming damage</td></tr></tbody></table><p>Stats increase through leveling, Enlightenment, and equipment (Wheels of Destiny and Covenants).</p><h2 id="card-composition" tabindex="-1">Card Composition <a class="header-anchor" href="#card-composition" aria-label="Permalink to &quot;Card Composition&quot;">​</a></h2><p>Each Awakener comes with a personal card set:</p><ul><li><strong>4 Command Cards</strong> — The Awakener&#39;s core abilities, drawn during battle</li><li><strong>1 Spirit Awakening Card</strong> — A powerful signature ability unique to each Awakener</li></ul><p>During combat, Awakeners also have access to <strong>Madness Burst</strong>, triggered for free when Madness Points reach 100.</p><h2 id="browse-awakeners" tabindex="-1">Browse Awakeners <a class="header-anchor" href="#browse-awakeners" aria-label="Permalink to &quot;Browse Awakeners&quot;">​</a></h2><p>Use the filter below to find Awakeners by realm, role, or rarity.</p>',21)),o(t),e[1]||(e[1]=a('<h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./list.html">Awakener List</a></li><li><a href="./leveling.html">Leveling Guide</a></li><li><a href="./enlightenment.html">Enlightenment System</a></li><li><a href="./team-building.html">Team Building</a></li><li><a href="./../cards/">Card System</a></li></ul>',2))])}const f=r(l,[["render",d]]);export{b as __pageData,f as default};
